+        await wasm.init_storage();
+        await wasm.save();
+        return true;
+      } catch (e) {
+        console.error('Save failed:', e);
+        return false;
+      }
+    },
+    has_saved_state: async () => {
+      try {
+        return await WasmModule.has_saved_state();
