+        context: &mut ExecutionContext,
+    ) -> Result<(), ExecutionError> {
+        // Get or create source node
+        let from_node = if let Some(var) = &pattern.from.variable {
+            if let Some(ContextValue::Node(n)) = context.get(var) {
