+                Direction::Incoming => self.graph.get_incoming_edges(&from_node.id),
+                Direction::Undirected => {
+                    let mut all = self.graph.get_outgoing_edges(&from_node.id);
+                    all.extend(self.graph.get_incoming_edges(&from_node.id));
+                    all
+                }
+            };
