+        Ok(ExecutionResult::new(vec![]))
+    }
+
+    fn execute_delete(
+        &mut self,
+        clause: &DeleteClause,
+        context: &ExecutionContext,
+    ) -> Result<ExecutionResult, ExecutionError> {
