+//! In-memory property graph storage for WASM-compatible Cypher execution
+
+use serde::{Deserialize, Serialize};
+use std::collections::HashMap;
+use thiserror::Error;
+
+pub type NodeId = String;
+pub type EdgeId = String;
+
+#[derive(Debug, Error)]
+pub enum GraphError {
+    #[error("Node not found: {0}")]
+    NodeNotFound(NodeId),
+    #[error("Edge not found: {0}")]
+    EdgeNotFound(EdgeId),
+    #[error("Invalid operation: {0}")]
+    InvalidOperation(String),
+}
+
+/// Property value that can be stored in nodes/edges
+#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
+pub enum Value {
+    Null,
+    Boolean(bool),
+    Integer(i64),
+    Float(f64),
+    String(String),
+    List(Vec<Value>),
+    Map(HashMap<String, Value>),
+}
+
+impl Value {
+    pub fn as_i64(&self) -> Option<i64> {
+        match self {
+            Value::Integer(n) => Some(*n),
+            _ => None,
+        }
+    }
+
+    pub fn as_f64(&self) -> Option<f64> {
+        match self {
+            Value::Float(f) => Some(*f),
+            Value::Integer(i) => Some(*i as f64),
+            _ => None,
+        }
+    }
+
+    pub fn as_str(&self) -> Option<&str> {
+        match self {
+            Value::String(s) => Some(s),
+            _ => None,
+        }
+    }
+
+    pub fn as_bool(&self) -> Option<bool> {
+        match self {
+            Value::Boolean(b) => Some(*b),
+            _ => None,
+        }
+    }
+}
+
+impl From<bool> for Value {
+    fn from(b: bool) -> Self {
+        Value::Boolean(b)
+    }
+}
+
+impl From<i64> for Value {
+    fn from(n: i64) -> Self {
+        Value::Integer(n)
+    }
+}
+
+impl From<f64> for Value {
+    fn from(f: f64) -> Self {
+        Value::Float(f)
+    }
+}
+
+impl From<String> for Value {
+    fn from(s: String) -> Self {
+        Value::String(s)
+    }
+}
+
+impl From<&str> for Value {
+    fn from(s: &str) -> Self {
+        Value::String(s.to_string())
+    }
+}
+
+/// Node in the property graph
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Node {
+    pub id: NodeId,
+    pub labels: Vec<String>,
+    pub properties: HashMap<String, Value>,
+}
+
+impl Node {
+    pub fn new(id: NodeId) -> Self {
+        Self {
+            id,
+            labels: Vec::new(),
+            properties: HashMap::new(),
+        }
+    }
+
+    pub fn with_label(mut self, label: String) -> Self {
+        self.labels.push(label);
+        self
+    }
+
+    pub fn with_labels(mut self, labels: Vec<String>) -> Self {
+        self.labels = labels;
+        self
+    }
+
+    pub fn with_property(mut self, key: String, value: Value) -> Self {
+        self.properties.insert(key, value);
+        self
+    }
+
+    pub fn has_label(&self, label: &str) -> bool {
+        self.labels.iter().any(|l| l == label)
+    }
+
+    pub fn get_property(&self, key: &str) -> Option<&Value> {
+        self.properties.get(key)
+    }
+
+    pub fn set_property(&mut self, key: String, value: Value) {
+        self.properties.insert(key, value);
+    }
+
+    pub fn remove_property(&mut self, key: &str) -> Option<Value> {
+        self.properties.remove(key)
+    }
+
+    pub fn add_label(&mut self, label: String) {
+        if !self.has_label(&label) {
+            self.labels.push(label);
+        }
+    }
+
+    pub fn remove_label(&mut self, label: &str) {
+        self.labels.retain(|l| l != label);
+    }
+}
+
+/// Edge/Relationship in the property graph
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub struct Edge {
+    pub id: EdgeId,
+    pub from: NodeId,
+    pub to: NodeId,
+    pub edge_type: String,
+    pub properties: HashMap<String, Value>,
+}
+
+impl Edge {
