+            TokenKind::Remove => Ok(Statement::Remove(self.parse_remove()?)),
+            TokenKind::Return => Ok(Statement::Return(self.parse_return()?)),
+            TokenKind::With => Ok(Statement::With(self.parse_with()?)),
