+    /// Export triple store state
+    fn export_triple_state(&self) -> storage::state::TripleStoreState {
+        use storage::state::*;
+
+        let triples: Vec<TripleState> = self.triple_store.all_triples()
+            .into_iter()
+            .enumerate()
+            .map(|(id, t)| {
+                TripleState {
