+/// SPARQL expression
+#[derive(Debug, Clone, Serialize, Deserialize)]
+pub enum Expression {
+    /// Variable reference
+    Variable(String),
+    /// Constant term
+    Term(RdfTerm),
+    /// Binary operation
+    Binary(Box<Expression>, BinaryOp, Box<Expression>),
+    /// Unary operation
+    Unary(UnaryOp, Box<Expression>),
+    /// Function call
+    Function(FunctionCall),
+    /// Aggregate function
+    Aggregate(Aggregate),
+    /// IN expression
+    In(Box<Expression>, Vec<Expression>),
+    /// NOT IN expression
+    NotIn(Box<Expression>, Vec<Expression>),
+    /// EXISTS subquery
+    Exists(Box<GraphPattern>),
+    /// NOT EXISTS subquery
+    NotExists(Box<GraphPattern>),
+    /// Conditional (IF)
+    If(Box<Expression>, Box<Expression>, Box<Expression>),
+    /// COALESCE
+    Coalesce(Vec<Expression>),
+    /// BOUND test
+    Bound(String),
+    /// isIRI test
+    IsIri(Box<Expression>),
+    /// isBlank test
+    IsBlank(Box<Expression>),
+    /// isLiteral test
+    IsLiteral(Box<Expression>),
+    /// isNumeric test
+    IsNumeric(Box<Expression>),
+    /// REGEX pattern matching
+    Regex(Box<Expression>, Box<Expression>, Option<Box<Expression>>),
+    /// LANG function
+    Lang(Box<Expression>),
+    /// DATATYPE function
+    Datatype(Box<Expression>),
+    /// STR function
+    Str(Box<Expression>),
+    /// IRI constructor
+    Iri(Box<Expression>),
+}
+
+impl Expression {
+    pub fn var(name: impl Into<String>) -> Self {
+        Self::Variable(name.into())
+    }
+
+    pub fn term(t: RdfTerm) -> Self {
+        Self::Term(t)
+    }
+
+    pub fn literal(value: impl Into<String>) -> Self {
+        Self::Term(RdfTerm::literal(value))
+    }
+
+    pub fn integer(value: i64) -> Self {
+        Self::Term(RdfTerm::Literal(Literal::integer(value)))
+    }
+
+    pub fn binary(left: Expression, op: BinaryOp, right: Expression) -> Self {
+        Self::Binary(Box::new(left), op, Box::new(right))
+    }
+
+    pub fn unary(op: UnaryOp, expr: Expression) -> Self {
+        Self::Unary(op, Box::new(expr))
+    }
+
+    pub fn and(left: Expression, right: Expression) -> Self {
+        Self::binary(left, BinaryOp::And, right)
+    }
+
+    pub fn or(left: Expression, right: Expression) -> Self {
+        Self::binary(left, BinaryOp::Or, right)
+    }
+
+    pub fn eq(left: Expression, right: Expression) -> Self {
+        Self::binary(left, BinaryOp::Eq, right)
+    }
+
+    pub fn neq(left: Expression, right: Expression) -> Self {
+        Self::binary(left, BinaryOp::NotEq, right)
+    }
+
+    pub fn lt(left: Expression, right: Expression) -> Self {
+        Self::binary(left, BinaryOp::Lt, right)
+    }
+
+    pub fn gt(left: Expression, right: Expression) -> Self {
+        Self::binary(left, BinaryOp::Gt, right)
+    }
+}
+
+/// Binary operators
