+    Or,
+    // Comparison
+    Eq,
+    NotEq,
+    Lt,
+    LtEq,
+    Gt,
+    GtEq,
+    // Arithmetic
+    Add,
+    Sub,
+    Mul,
+    Div,
+    // String
+    SameTerm,
+    LangMatches,
+}
